const cfg = msg.cfg;
const root = global.get("homeassistant");
const states = root && root.homeAssistant && root.homeAssistant.states ? root.homeAssistant.states : {};

function num(entityId) {
  if (!entityId || !states[entityId]) return null;
  const n = Number(states[entityId].state);
  return Number.isFinite(n) ? n : null;
}
function str(entityId) {
  if (!entityId || !states[entityId]) return "";
  return String(states[entityId].state || "").trim();
}

msg.inputs = {
  solarEnergy: cfg.solarEnabled && cfg.solarInputMode === "energy" ? num(cfg.solarEnergyEntity) : null,
  loadEnergy: cfg.loadEnabled && cfg.loadInputMode === "energy" ? num(cfg.loadEnergyEntity) : null,
