  gridImportPower: cfg.gridEnabled && cfg.gridInputMode === "power" ? num(cfg.gridImportPowerEntity) : null,
  gridExportPower: cfg.gridEnabled && cfg.gridInputMode === "power" ? num(cfg.gridExportPowerEntity) : null,
  batteryChargePower: cfg.batteryEnabled && cfg.batteryInputMode === "power" ? num(cfg.batteryChargePowerEntity) : null,
  batteryDischargePower: cfg.batteryEnabled && cfg.batteryInputMode === "power" ? num(cfg.batteryDischargePowerEntity) : null,
