};
return msg;

const cfg = msg.cfg;
const inputs = msg.inputs;

function safe(v){ return Number.isFinite(v) ? v : null; }
function add(a,b){ return Number(((a||0)+(b||0)).toFixed(6)); }
function subPos(cur, prev){ if(!Number.isFinite(cur)||!Number.isFinite(prev)) return 0; const d=cur-prev; return d>=0 ? Number(d.toFixed(6)) : 0; }

function dateParts(tz){
  const parts = new Intl.DateTimeFormat('en-CA',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false}).formatToParts(new Date());
  const m={};
  for(const p of parts){ if(p.type!=='literal') m[p.type]=p.value; }
  return { year:m.year, month:m.month, day:m.day, hour:m.hour, minute:m.minute, second:m.second, dayKey:`${m.year}-${m.month}-${m.day}`, monthKey:`${m.year}-${m.month}`, yearKey:`${m.year}` };
}

const now = dateParts(cfg.tz || 'UTC');
let store = flow.get('finance_store','persistent') || {
  keys:{ dayKey:now.dayKey, monthKey:now.monthKey, yearKey:now.yearKey },
  previousEnergyCounters:{ solarEnergy:null, loadEnergy:null, gridImportEnergy:null, gridExportEnergy:null, batteryChargeEnergy:null, batteryDischargeEnergy:null },
  accumulators:{
    day:{ solar:0, load:0, gridImport:0, gridExport:0, batteryCharge:0, batteryDischarge:0 },
    month:{ solar:0, load:0, gridImport:0, gridExport:0, batteryCharge:0, batteryDischarge:0 },
    year:{ solar:0, load:0, gridImport:0, gridExport:0, batteryCharge:0, batteryDischarge:0 }
  },
  meta:{ lastTempoColor:'', lastTariffName:'', lastTariffPeriod:'', lastRun:'' }
};

if(store.keys.dayKey !== now.dayKey){ store.accumulators.day = { solar:0, load:0, gridImport:0, gridExport:0, batteryCharge:0, batteryDischarge:0 }; }
if(store.keys.monthKey !== now.monthKey){ store.accumulators.month = { solar:0, load:0, gridImport:0, gridExport:0, batteryCharge:0, batteryDischarge:0 }; }
if(store.keys.yearKey !== now.yearKey){ store.accumulators.year = { solar:0, load:0, gridImport:0, gridExport:0, batteryCharge:0, batteryDischarge:0 }; }
store.keys = { dayKey:now.dayKey, monthKey:now.monthKey, yearKey:now.yearKey };

const deltas = { solar:0, load:0, gridImport:0, gridExport:0, batteryCharge:0, batteryDischarge:0 };
if(cfg.solarInputMode==='energy'){ deltas.solar = subPos(safe(inputs.solarEnergy), safe(store.previousEnergyCounters.solarEnergy)); store.previousEnergyCounters.solarEnergy = safe(inputs.solarEnergy); }
if(cfg.loadInputMode==='energy'){ deltas.load = subPos(safe(inputs.loadEnergy), safe(store.previousEnergyCounters.loadEnergy)); store.previousEnergyCounters.loadEnergy = safe(inputs.loadEnergy); }
if(cfg.gridInputMode==='energy'){
  deltas.gridImport = subPos(safe(inputs.gridImportEnergy), safe(store.previousEnergyCounters.gridImportEnergy));
  deltas.gridExport = subPos(safe(inputs.gridExportEnergy), safe(store.previousEnergyCounters.gridExportEnergy));
  store.previousEnergyCounters.gridImportEnergy = safe(inputs.gridImportEnergy);
  store.previousEnergyCounters.gridExportEnergy = safe(inputs.gridExportEnergy);
}
if(cfg.batteryEnabled && cfg.batteryInputMode==='energy'){
  deltas.batteryCharge = subPos(safe(inputs.batteryChargeEnergy), safe(store.previousEnergyCounters.batteryChargeEnergy));
  deltas.batteryDischarge = subPos(safe(inputs.batteryDischargeEnergy), safe(store.previousEnergyCounters.batteryDischargeEnergy));
  store.previousEnergyCounters.batteryChargeEnergy = safe(inputs.batteryChargeEnergy);
  store.previousEnergyCounters.batteryDischargeEnergy = safe(inputs.batteryDischargeEnergy);
}

for(const p of ['day','month','year']){
  store.accumulators[p].solar = add(store.accumulators[p].solar, deltas.solar);
  store.accumulators[p].load = add(store.accumulators[p].load, deltas.load);
  store.accumulators[p].gridImport = add(store.accumulators[p].gridImport, deltas.gridImport);
  store.accumulators[p].gridExport = add(store.accumulators[p].gridExport, deltas.gridExport);
  store.accumulators[p].batteryCharge = add(store.accumulators[p].batteryCharge, deltas.batteryCharge);
  store.accumulators[p].batteryDischarge = add(store.accumulators[p].batteryDischarge, deltas.batteryDischarge);
}

store.meta.lastRun = new Date().toISOString();
flow.set('finance_store', store, 'persistent');
msg.time = now;
msg.deltas = deltas;
msg.store = store;
return msg;

const cfg = msg.cfg;
const inputs = msg.inputs;
const store = msg.store;
const time = msg.time;

function round(v,d=4){ return Number((Number(v||0)).toFixed(d)); }
function hhmmToMinutes(s){ if(!s || !/^\d{2}:\d{2}$/.test(s)) return null; const [h,m]=s.split(':').map(Number); if(h<0||h>23||m<0||m>59) return null; return h*60+m; }
function minuteOfDay(t){ return (Number(t.hour)*60)+Number(t.minute); }
function isMinuteInRange(minute,start,end){ const s=hhmmToMinutes(start); const e=hhmmToMinutes(end); if(s===null||e===null) return false; if(s===e) return true; if(s<e) return minute>=s && minute<e; return minute>=s || minute<e; }
function normalizeTempoColor(v){ const s=String(v||'').trim().toLowerCase(); if(s.includes('bleu')||s==='blue') return 'blue'; if(s.includes('blanc')||s==='white') return 'white'; if(s.includes('rouge')||s==='red') return 'red'; return 'unknown'; }

function currentTariff(){
  const minute = minuteOfDay(time);
  if(cfg.contractType === 'fixed'){
    return { mode:'fixed', name:'fixed', period:'fixed', importPrice:Number(cfg.fixedImportPrice||0), exportPrice:Number(cfg.fixedExportPrice||0), tempoColor:'' };
  }
  if(cfg.contractType === 'time_based'){
    const tariffs = [cfg.tariff1,cfg.tariff2,cfg.tariff3,cfg.tariff4].filter(t => t && t.name && t.start && t.end);
    for(const t of tariffs){
      if(isMinuteInRange(minute,t.start,t.end)){
        return { mode:'time_based', name:t.name, period:t.name, importPrice:Number(t.price||0), exportPrice:Number(cfg.fixedExportPrice||0), tempoColor:'' };
      }
    }
    return { mode:'time_based', name:'unmatched', period:'unmatched', importPrice:0, exportPrice:Number(cfg.fixedExportPrice||0), tempoColor:'' };
  }
  if(cfg.contractType === 'tempo'){
    const color = normalizeTempoColor(inputs.tempoColorRaw);
    const hc =
      isMinuteInRange(minute, cfg.tempo.hcSlot1Start, cfg.tempo.hcSlot1End) ||
      (cfg.tempo.hcSlot2Start && cfg.tempo.hcSlot2End && isMinuteInRange(minute, cfg.tempo.hcSlot2Start, cfg.tempo.hcSlot2End)) ||
      (cfg.tempo.hcSlot3Start && cfg.tempo.hcSlot3End && isMinuteInRange(minute, cfg.tempo.hcSlot3Start, cfg.tempo.hcSlot3End));
    let importPrice = 0;
    let name = 'tempo_unknown';
    let period = hc ? 'hc' : 'hp';
    if(color==='blue'){ importPrice = hc ? Number(cfg.tempo.blueHc||0) : Number(cfg.tempo.blueHp||0); name = hc ? 'tempo_blue_hc' : 'tempo_blue_hp'; }
    else if(color==='white'){ importPrice = hc ? Number(cfg.tempo.whiteHc||0) : Number(cfg.tempo.whiteHp||0); name = hc ? 'tempo_white_hc' : 'tempo_white_hp'; }
    else if(color==='red'){ importPrice = hc ? Number(cfg.tempo.redHc||0) : Number(cfg.tempo.redHp||0); name = hc ? 'tempo_red_hc' : 'tempo_red_hp'; }
    return { mode:'tempo', name, period, importPrice, exportPrice:Number(cfg.fixedExportPrice||0), tempoColor:color };
  }
  return { mode:'fixed', name:'fixed', period:'fixed', importPrice:Number(cfg.fixedImportPrice||0), exportPrice:Number(cfg.fixedExportPrice||0), tempoColor:'' };
}

const tariff = currentTariff();

function proratedSubscription(periodName){
  const p = Number(cfg.monthlySubscriptionPrice||0);
  if(!p) return 0;
  if(periodName==='day'){
    const daysInMonth = new Date(Number(time.year), Number(time.month), 0).getDate();
    return p / daysInMonth;
  }
  if(periodName==='month') return p;
  if(periodName==='year') return p * 12;
  return 0;
}

function periodFinance(acc, periodName){
  const importEnergy = Number(acc.gridImport||0);
  const exportEnergy = Number(acc.gridExport||0);
  const loadEnergy = Number(acc.load||0);
  const solarEnergy = Number(acc.solar||0);
  const batteryDischarge = Number(acc.batteryDischarge||0);
  const batteryCharge = Number(acc.batteryCharge||0);
  const costImport = importEnergy * Number(tariff.importPrice||0);
  const revenueExport = exportEnergy * Number(tariff.exportPrice||0);
  const theoreticalNoSolarCost = loadEnergy * Number(tariff.importPrice||0);
  const subscriptionCost = proratedSubscription(periodName);
  const realTotalWithSubscription = costImport + subscriptionCost - revenueExport;
  const savingsVsNoSolar = theoreticalNoSolarCost - costImport + revenueExport;
  let selfSufficiencyPct = 0;
  if(loadEnergy > 0){ selfSufficiencyPct = ((Math.max(0, loadEnergy - importEnergy)) / loadEnergy) * 100; }
  let gridDependencyPct = 0;
  if(loadEnergy > 0){ gridDependencyPct = (importEnergy / loadEnergy) * 100; }
  return {
    energy:{ solar_kwh:round(solarEnergy), load_kwh:round(loadEnergy), grid_import_kwh:round(importEnergy), grid_export_kwh:round(exportEnergy), battery_charge_kwh:round(batteryCharge), battery_discharge_kwh:round(batteryDischarge) },
    finance:{ import_cost:round(costImport), export_revenue:round(revenueExport), subscription_cost:round(subscriptionCost), theoretical_no_solar_cost:round(theoreticalNoSolarCost), real_total_with_subscription:round(realTotalWithSubscription), savings_vs_no_solar:round(savingsVsNoSolar) },
    ratios:{ self_sufficiency_pct:round(selfSufficiencyPct,2), grid_dependency_pct:round(gridDependencyPct,2) }
  };
}

store.meta.lastTempoColor = tariff.tempoColor;
store.meta.lastTariffName = tariff.name;
store.meta.lastTariffPeriod = tariff.period;
flow.set('finance_store', store, 'persistent');

msg.payload = {
