    battery_discharge_energy_counter:inputs.batteryDischargeEnergy,
    solar_power_w:inputs.solarPower,
    load_power_w:inputs.loadPower,
    grid_import_power_w:inputs.gridImportPower,
    grid_export_power_w:inputs.gridExportPower,
    battery_charge_power_w:inputs.batteryChargePower,
    battery_discharge_power_w:inputs.batteryDischargePower
  },
  deltas:{
    solar_kwh:round(msg.deltas.solar,6),
    load_kwh:round(msg.deltas.load,6),
    grid_import_kwh:round(msg.deltas.gridImport,6),
    grid_export_kwh:round(msg.deltas.gridExport,6),
    battery_charge_kwh:round(msg.deltas.batteryCharge,6),
    battery_discharge_kwh:round(msg.deltas.batteryDischarge,6)
  },
  day: periodFinance(store.accumulators.day, 'day'),
  month: periodFinance(store.accumulators.month, 'month'),
  year: periodFinance(store.accumulators.year, 'year')
};
return msg;

